mapper.select:
SELECT id, project_code, name, category, cost_price, retail_price, price, unit, invoice_item, body_part, allow_member_discount, status, creator, remark, created_at, updated_at, deleted FROM clinic_check_project WHERE deleted = 0
AND (project_code LIKE CONCAT('%', #{keyword}, '%') OR name LIKE CONCAT('%', #{keyword}, '%') OR category LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY id DESC LIMIT #{size} OFFSET #{offset}

mapper.update:
UPDATE clinic_check_project
SET deleted = 1, updated_at = NOW()
WHERE id = #{id}
